const sourceNode = $('Webhook: Auto Deposit Intake').first();
const raw = sourceNode.json.body ?? sourceNode.json ?? {};
const deposits = Array.isArray(raw.deposits) ? raw.deposits : [];

function digitsOnly(value) {
  return String(value ?? '').replace(/\D/g, '');
}

function parseInteger(value) {
  if (typeof value === 'number') return Number.isFinite(value) ? Math.trunc(value) : 0;
  const parsed = Number(String(value ?? '').replace(/,/g, '').replace(/원/g, '').trim());
  return Number.isFinite(parsed) ? Math.trunc(parsed) : 0;
}

function normalizeName(value) {
  return String(value ?? '')
    .toLowerCase()
    .replace(/\s+/g, '')
    .replace(/[()\-.,/]/g, '')
    .replace(/님/g, '')
    .replace(/회장/g, '')
    .replace(/이사장/g, '')
    .replace(/대표/g, '')
    .trim();
}

function normalizeBusinessNo(value) {
  return String(value ?? '').replace(/\D/g, '');
}

function normalizeDate(value) {
  const text = String(value ?? '').trim();
  const iso = text.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (iso) return iso[0];
  const dotted = text.match(/(\d{4})[./](\d{1,2})[./](\d{1,2})/);
  if (dotted) return dotted[1] + '-' + dotted[2].padStart(2, '0') + '-' + dotted[3].padStart(2, '0');
  return '';
}

function parseCustomerAccountingMeta(memo) {
  const prefix = '[ACCOUNTING_CUSTOMER_META]';
  const line = String(memo ?? '')
    .split('\n')
    .map((entry) => entry.trim())
    .find((entry) => entry.startsWith(prefix));
  if (!line) {
    return { depositBalance: 0, refundPendingBalance: 0, depositorAliases: [], autoDepositDisabled: false, autoDepositPriority: 0, events: [] };
  }
  try {
    const parsed = JSON.parse(line.slice(prefix.length).trim());
    const aliases = Array.isArray(parsed.depositorAliases)
      ? parsed.depositorAliases.map((entry) => String(entry ?? '').trim()).filter(Boolean)
      : [];
    return {
      depositBalance: Math.max(0, parseInteger(parsed.depositBalance)),
      refundPendingBalance: Math.max(0, parseInteger(parsed.refundPendingBalance)),
      depositorAliases: aliases,
      autoDepositDisabled: parsed.autoDepositDisabled === true,
      autoDepositPriority: Math.max(0, parseInteger(parsed.autoDepositPriority)),
      events: Array.isArray(parsed.events) ? parsed.events : [],
    };
  } catch {
    return { depositBalance: 0, refundPendingBalance: 0, depositorAliases: [], autoDepositDisabled: false, autoDepositPriority: 0, events: [] };
  }
}

function parseLegacyReceivableMemo(memo) {
  const prefix = '[LEGACY_RECEIVABLE_META]';
  const line = String(memo ?? '')
    .split('\n')
    .map((entry) => entry.trim())
    .find((entry) => entry.startsWith(prefix));
  if (!line) {
    return { settledAmount: 0, settlements: [] };
  }
  try {
    const parsed = JSON.parse(line.slice(prefix.length).trim());
    const settlements = Array.isArray(parsed.settlements) ? parsed.settlements : [];
    const settledAmount = Math.max(
      parseInteger(parsed.settledAmount),
      settlements.reduce((sum, entry) => sum + Math.max(0, parseInteger(entry.amount)), 0),
    );
    return { settledAmount, settlements };
  } catch {
    return { settledAmount: 0, settlements: [] };
  }
}

function serializeLegacyReceivableMemo(memo, nextState) {
  const prefix = '[LEGACY_RECEIVABLE_META]';
  const visibleLines = String(memo ?? '')
    .replace(/\r\n/g, '\n')
    .split('\n')
    .filter((line) => line.trim() && !line.trim().startsWith(prefix));
  const settlements = Array.isArray(nextState.settlements) ? nextState.settlements : [];
  if (settlements.length === 0 && parseInteger(nextState.settledAmount) <= 0) {
    return visibleLines.join('\n').trim();
  }
  const payload = {
    settledAmount: Math.max(
      parseInteger(nextState.settledAmount),
      settlements.reduce((sum, entry) => sum + Math.max(0, parseInteger(entry.amount)), 0),
    ),
    settlements,
  };
  return [...visibleLines, prefix + ' ' + JSON.stringify(payload)].join('\n').trim();
}

function parseInvoiceDepositUsedAmount(memo) {
  const prefix = '[ACCOUNTING_INVOICE_META]';
  const line = String(memo ?? '')
    .split('\n')
    .map((entry) => entry.trim())
    .find((entry) => entry.startsWith(prefix));
  if (!line) return 0;
  try {
    const parsed = JSON.parse(line.slice(prefix.length).trim());
    return Math.max(0, parseInteger(parsed.depositUsedAmount));
  } catch {
    return 0;
  }
}

function getCustomerLookupTokens(customer, extraValues = []) {
  const meta = parseCustomerAccountingMeta(customer.memo);
  return [
    customer.name,
    customer.book_name,
    ...meta.depositorAliases,
    ...extraValues,
  ]
    .map(normalizeName)
    .filter(Boolean);
}

function buildLegacyReceivableBaseline(customer, tradebookByLegacyId, fiscalPayload) {
  const legacyId = String(customer.legacy_id ?? '').trim();
  if (!legacyId) return 0;
  const snapshot = tradebookByLegacyId?.[legacyId];
  if (!snapshot) return 0;
  if (String(snapshot.report_print ?? '').trim() === '거래종료') return 0;
  const fiscalYear = fiscalPayload?.years?.[String(fiscalPayload.currentFiscalYear)];
  const fiscalAmount = fiscalYear?.receivablesByLegacyId?.[legacyId];
  const rawBaseline = typeof fiscalAmount === 'number'
    ? fiscalAmount
    : Math.abs(Math.min(0, parseInteger(snapshot.balance)));
  if (!rawBaseline) return 0;
  const memoState = parseLegacyReceivableMemo(customer.memo);
  return Math.max(0, rawBaseline - memoState.settledAmount);
}

const customers = $('NocoDB Get Customers').first().json.list ?? [];
const invoices = $('NocoDB Get Open Invoices').first().json.list ?? [];
const legacySnapshots = $('HTTP Get Legacy Snapshots').first().json ?? {};
const fiscalSnapshots = $('HTTP Get Fiscal Snapshots').first().json ?? {};

const tradebookByLegacyId = legacySnapshots.tradebookByLegacyId ?? {};
const currentFiscalYearPayload = fiscalSnapshots ?? {};

const customerById = new Map(customers.map((customer) => [Number(customer.Id), customer]));
const outstandingByCustomer = new Map(customers.map((customer) => [Number(customer.Id), Math.max(0, parseInteger(customer.outstanding_balance))]));
const legacyMemoByCustomer = new Map(customers.map((customer) => [Number(customer.Id), String(customer.memo ?? '')]));

const normalizedDeposits = deposits
  .map((deposit, index) => {
    const amount = Math.max(0, parseInteger(deposit.amount));
    const sender = String(deposit.sender ?? '').trim();
    const occurredAt = String(deposit.occurredAt ?? '').trim();
    const occurredDate = normalizeDate(occurredAt);
    if (!amount || !sender || !occurredDate) return null;
    return {
      index,
      sender,
      senderKey: normalizeName(sender),
      amount,
      occurredAt,
      occurredDate,
      note: String(deposit.note ?? '').trim(),
      externalId: String(deposit.externalId ?? '').trim() || ('deposit-' + index + '-' + amount + '-' + occurredDate),
      raw: deposit,
    };
  })
  .filter(Boolean);

const exactActions = [];
const reviewEntries = [];
const unmatchedEntries = [];
const appliedCustomerIds = new Set();

for (const deposit of normalizedDeposits) {
  const invoiceCandidates = invoices
    .map((invoice) => {
      const customerId = Number(invoice.customer_id ?? 0);
      if (!customerId) return null;
      const fallbackRemaining = Math.max(
        0,
        parseInteger(invoice.total_amount) - parseInteger(invoice.paid_amount) - parseInvoiceDepositUsedAmount(invoice.memo),
      );
      const customer = customerById.get(customerId) ?? {
        Id: customerId,
        name: String(invoice.customer_name ?? '').trim(),
        book_name: '',
        memo: '',
        outstanding_balance: fallbackRemaining,
      };
      const customerMeta = parseCustomerAccountingMeta(customer.memo);
      if (customerMeta.autoDepositDisabled) return null;
      const remaining = fallbackRemaining;
      const tokens = getCustomerLookupTokens(customer, [invoice.customer_name]);
      const senderMatched = tokens.some((token) => token && deposit.senderKey.includes(token));
      const exactAmountMatched = remaining === deposit.amount;
      const partialAmountMatched = senderMatched && remaining > 0 && deposit.amount > 0 && deposit.amount < remaining;
      const overAmountMatched = senderMatched && remaining > 0 && deposit.amount > remaining;
      if (!exactAmountMatched && !partialAmountMatched && !overAmountMatched) return null;
      const score = (senderMatched ? 100 : 60) + Math.min(30, customerMeta.autoDepositPriority);
      return {
        key: 'invoice-' + invoice.Id,
        kind: 'invoice',
        confidence: exactAmountMatched && (senderMatched || invoices.filter((candidate) => {
          const candidateRemaining = Math.max(
            0,
            parseInteger(candidate.total_amount) - parseInteger(candidate.paid_amount) - parseInvoiceDepositUsedAmount(candidate.memo),
          );
          return candidateRemaining === deposit.amount;
        }).length === 1) ? 'exact' : 'review',
        score,
        customerId,
        customerName: customer.name,
        invoiceId: Number(invoice.Id),
        invoiceNo: invoice.invoice_no,
        reason: partialAmountMatched
          ? '입금자명은 맞지만 금액이 일부만 들어와 부분 입금 검토가 필요합니다.'
          : overAmountMatched
          ? '입금자명은 맞지만 금액이 명세표 잔액보다 커서 초과 입금 검토가 필요합니다.'
          : senderMatched
          ? '입금자명과 고객명이 맞고 열린 명세표 잔액과 금액이 같습니다.'
          : '열린 명세표 잔액과 입금 금액이 같습니다.',
      };
    })
    .filter(Boolean);

  const legacyCandidates = customers
    .map((customer) => {
      const customerMeta = parseCustomerAccountingMeta(customer.memo);
      if (customerMeta.autoDepositDisabled) return null;
      const legacyBaseline = buildLegacyReceivableBaseline(customer, tradebookByLegacyId, currentFiscalYearPayload);
      const tokens = getCustomerLookupTokens(customer);
      const senderMatched = tokens.some((token) => token && deposit.senderKey.includes(token));
      const exactAmountMatched = legacyBaseline === deposit.amount;
      const partialAmountMatched = senderMatched && legacyBaseline > 0 && deposit.amount > 0 && deposit.amount < legacyBaseline;
      const overAmountMatched = senderMatched && legacyBaseline > 0 && deposit.amount > legacyBaseline;
      if (!exactAmountMatched && !partialAmountMatched && !overAmountMatched) return null;
      const score = (senderMatched ? 95 : 55) + Math.min(30, customerMeta.autoDepositPriority);
      return {
        key: 'legacy-' + customer.Id,
        kind: 'legacy',
        confidence: exactAmountMatched && (senderMatched || customers.filter((candidate) => buildLegacyReceivableBaseline(candidate, tradebookByLegacyId, currentFiscalYearPayload) === deposit.amount).length === 1) ? 'exact' : 'review',
        score,
        customerId: Number(customer.Id),
        customerName: customer.name,
        reason: partialAmountMatched
          ? '입금자명은 맞지만 기존 장부 받을 돈보다 적게 들어와 부분 입금 검토가 필요합니다.'
          : overAmountMatched
          ? '입금자명은 맞지만 기존 장부 받을 돈보다 많이 들어와 초과 입금 검토가 필요합니다.'
          : senderMatched
          ? '입금자명과 고객명이 맞고 기존 장부 받을 돈과 금액이 같습니다.'
          : '기존 장부 받을 돈과 입금 금액이 같습니다.',
      };
    })
    .filter(Boolean);

  const candidates = [...invoiceCandidates, ...legacyCandidates]
    .sort((left, right) => right.score - left.score)
    .filter((candidate, index, list) => list.findIndex((entry) => entry.key === candidate.key) === index);

  const best = candidates[0];
  const hasUniqueBest = best && (!candidates[1] || best.score > candidates[1].score);

  if (best && best.confidence === 'exact' && hasUniqueBest) {
    const customer = customerById.get(best.customerId) ?? (best.kind === 'invoice'
      ? {
          Id: best.customerId,
          name: best.customerName,
          book_name: '',
          memo: '',
          outstanding_balance: deposit.amount,
        }
      : null);
    if (!customer) {
      unmatchedEntries.push({
        sender: deposit.sender,
        amount: deposit.amount,
        occurredAt: deposit.occurredAt,
        externalId: deposit.externalId,
        reason: '고객 정보를 찾지 못했습니다.',
      });
      continue;
    }

    const currentOutstanding = outstandingByCustomer.get(best.customerId) ?? Math.max(0, parseInteger(customer.outstanding_balance));
    const nextOutstanding = Math.max(0, currentOutstanding - deposit.amount);
    outstandingByCustomer.set(best.customerId, nextOutstanding);
    appliedCustomerIds.add(best.customerId);

    if (best.kind === 'invoice') {
      const invoice = invoices.find((entry) => Number(entry.Id) === best.invoiceId);
      const previousPaid = parseInteger(invoice?.paid_amount);
      exactActions.push({
        kind: 'invoice',
        deposit,
        customerId: best.customerId,
        customerName: best.customerName,
        invoiceId: best.invoiceId,
        invoiceNo: best.invoiceNo,
        invoicePatch: {
          paid_amount: previousPaid + deposit.amount,
          current_balance: 0,
          payment_status: 'paid',
          payment_method: '계좌이체',
          paid_date: deposit.occurredDate,
        },
        customerPatch: {
          outstanding_balance: nextOutstanding,
        },
        reason: best.reason,
      });
      continue;
    }

    const previousMemo = legacyMemoByCustomer.get(best.customerId) ?? String(customer.memo ?? '');
    const memoState = parseLegacyReceivableMemo(previousMemo);
    const nextMemo = serializeLegacyReceivableMemo(previousMemo, {
      settledAmount: memoState.settledAmount + deposit.amount,
      settlements: [
        ...memoState.settlements,
        {
          amount: deposit.amount,
          date: deposit.occurredDate,
          method: '계좌이체',
          operator: '자동입금',
          accountLabel: 'email_imap',
          createdAt: new Date().toISOString(),
        },
      ],
    });
    legacyMemoByCustomer.set(best.customerId, nextMemo);
    exactActions.push({
      kind: 'legacy',
      deposit,
      customerId: best.customerId,
      customerName: best.customerName,
      customerPatch: {
        outstanding_balance: nextOutstanding,
        memo: nextMemo,
      },
      reason: best.reason,
    });
    continue;
  }

  if (candidates.length > 0) {
    reviewEntries.push({
      sender: deposit.sender,
      amount: deposit.amount,
      occurredAt: deposit.occurredAt,
      externalId: deposit.externalId,
      candidates: candidates.slice(0, 3).map((candidate) => ({
        kind: candidate.kind,
        customerId: candidate.customerId,
        customerName: candidate.customerName,
        invoiceId: candidate.invoiceId ?? null,
        invoiceNo: candidate.invoiceNo ?? null,
        reason: candidate.reason,
        score: candidate.score,
      })),
    });
  } else {
    unmatchedEntries.push({
      sender: deposit.sender,
      amount: deposit.amount,
      occurredAt: deposit.occurredAt,
      externalId: deposit.externalId,
      reason: '정확히 일치하는 고객이나 미수 금액을 찾지 못했습니다.',
    });
  }
}

return [{
  json: {
    source: String(raw.source ?? 'unknown'),
    exactActions,
    reviewEntries,
    unmatchedEntries,
    appliedCustomerIds: Array.from(appliedCustomerIds),
    summary: {
      total: normalizedDeposits.length,
      exact: exactActions.length,
      review: reviewEntries.length,
      unmatched: unmatchedEntries.length,
    },
  },
}];

const plan = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const now = new Date().toISOString();
const queue = Array.isArray(staticData.reviewQueue) ? staticData.reviewQueue : [];

function normalizeQueueId(entry, status) {
  const externalId = String(entry.externalId ?? '').trim();
  if (externalId) return externalId;
  return [status, String(entry.sender ?? '').trim(), String(entry.amount ?? 0), String(entry.occurredAt ?? '').trim()].join('::');
}

function upsertQueueEntry(status, entry) {
  const queueId = normalizeQueueId(entry, status);
  const nextItem = {
    queueId,
    status,
    sender: String(entry.sender ?? '').trim(),
    amount: Number(entry.amount ?? 0) || 0,
    occurredAt: String(entry.occurredAt ?? '').trim(),
    externalId: String(entry.externalId ?? '').trim(),
    source: String(plan.source ?? 'unknown'),
    reason: String(entry.reason ?? '').trim(),
    candidates: Array.isArray(entry.candidates) ? entry.candidates : [],
    updatedAt: now,
    createdAt: now,
    resolvedAt: null,
    resolvedBy: null,
    resolvedNote: null,
  };

  const existingIndex = queue.findIndex((item) => item.queueId === queueId);
  if (existingIndex >= 0) {
    const prev = queue[existingIndex];
    if (prev.status === 'resolved' || prev.status === 'dismissed') return 0;
    queue[existingIndex] = {
      ...prev,
      ...nextItem,
      createdAt: prev.createdAt ?? now,
    };
    return 1;
  }

  queue.unshift(nextItem);
  return 1;
}

let upserted = 0;
for (const entry of plan.reviewEntries || []) upserted += upsertQueueEntry('review', entry);
for (const entry of plan.unmatchedEntries || []) upserted += upsertQueueEntry('unmatched', entry);

staticData.reviewQueue = queue.slice(0, 500);

return [{
  json: {
    ...plan,
    queueSummary: {
      upserted,
      pending: staticData.reviewQueue.filter((item) => item.status === 'review' || item.status === 'unmatched').length,
      total: staticData.reviewQueue.length,
    },
  },
}];

const plan = $('Code: Persist Review Queue').first().json;
return [{ json: {
  ok: true,
  source: plan.source,
  summary: plan.summary,
  queueSummary: plan.queueSummary ?? null,
  reviewEntries: plan.reviewEntries,
  unmatchedEntries: plan.unmatchedEntries,
}}];

const staticData = $getWorkflowStaticData('global');
const req = $input.first().json;
const body = req.body ?? req ?? {};
const query = req.query ?? {};
const queue = Array.isArray(staticData.reviewQueue) ? staticData.reviewQueue : [];
const action = String(body.action ?? query.action ?? 'list').trim() || 'list';
const queueId = String(body.queueId ?? query.queueId ?? '').trim();
const now = new Date().toISOString();

function summarize(items) {
  return {
    total: items.length,
    review: items.filter((item) => item.status === 'review').length,
    unmatched: items.filter((item) => item.status === 'unmatched').length,
    resolved: items.filter((item) => item.status === 'resolved').length,
    dismissed: items.filter((item) => item.status === 'dismissed').length,
  };
}

if (action === 'list') {
  return [{
    json: {
      ok: true,
      items: [...queue].sort((a, b) => String(b.updatedAt ?? '').localeCompare(String(a.updatedAt ?? ''))),
      summary: summarize(queue),
    },
  }];
}

if (action === 'dismiss') {
  const index = queue.findIndex((item) => item.queueId === queueId);
  if (index < 0) {
    return [{ json: { ok: false, error: 'QUEUE_NOT_FOUND' } }];
  }
  queue[index] = {
    ...queue[index],
    status: 'dismissed',
    resolvedAt: now,
    resolvedBy: String(body.resolvedBy ?? 'manual').trim() || 'manual',
    resolvedNote: String(body.note ?? '').trim() || null,
    updatedAt: now,
  };
  staticData.reviewQueue = queue;
  return [{ json: { ok: true, item: queue[index], summary: summarize(queue) } }];
}

if (action === 'restore') {
  const index = queue.findIndex((item) => item.queueId === queueId);
  if (index < 0) {
    return [{ json: { ok: false, error: 'QUEUE_NOT_FOUND' } }];
  }
  queue[index] = {
    ...queue[index],
    status: queue[index].candidates?.length ? 'review' : 'unmatched',
    resolvedAt: null,
    resolvedBy: null,
    resolvedNote: null,
    updatedAt: now,
  };
  staticData.reviewQueue = queue;
  return [{ json: { ok: true, item: queue[index], summary: summarize(queue) } }];
}

if (action === 'clearResolved') {
  staticData.reviewQueue = queue.filter((item) => !['resolved', 'dismissed'].includes(item.status));
  return [{ json: { ok: true, summary: summarize(staticData.reviewQueue) } }];
}

return [{ json: { ok: false, error: 'UNSUPPORTED_ACTION', action } }];
